// 接案 vs 全職：沒有誰比較好，看適合誰
const compare = {
  "接案 / 自由工作": { 收入: "上不封頂但不穩", 自由: "高（自己排時間）", 風險: "要自己找案、沒勞保" },
  "全職": { 收入: "穩定月薪", 自由: "低（聽公司的）", 風險: "低、有保障" },
};
for (const [type, info] of Object.entries(compare)) {
  console.log("【" + type + "】收入:" + info.收入 + "｜自由:" + info.自由 + "｜風險:" + info.風險);
}

// 簡單報價：工時 x 時薪 + 緩衝（改稿 / 溝通 / 測試）
function quote(hours, rate, buffer = 1.2) {
  return Math.round(hours * rate * buffer);
}
console.log("40 小時 x 時薪 1000，含 20% 緩衝：NT$", quote(40, 1000));
console.log("提醒：報價要含改稿、溝通、測試，不是只算寫 code");

// 把一次性收入變長期：加上月費維護
const project = 80000;   // 一次性開發費
const monthly = 5000;    // 月費維護
const yearTotal = project + monthly * 12;
console.log("一次性開發：NT$", project);
console.log("一年含維護：NT$", yearTotal, "（多了穩定的被動收入）");

// 接案客戶的 5 大來源（主動經營，不靠運氣）
const sources = [
  "人脈轉介（成交率最高）",
  "外包平台（104 外包 / Upwork）",
  "作品集 / 個人網站",
  "社群經營（FB 社團 / IG）",
  "舊客戶回購",
];
sources.forEach((s, i) => console.log((i + 1) + ". " + s));

// 合約 + 訂金保護自己
const total = 60000;
const deposit = total * 0.3;   // 訂金 30%
console.log("總價：NT$", total);
console.log("簽約先收訂金 30%：NT$", deposit);
console.log("尾款驗收後付清；合約寫明範圍、改稿次數、付款節點");
